mapper.select:
SELECT EXISTS (
	SELECT 1
	FROM spots
	WHERE id = #{spotId}
		AND active = 1
)

mapper.update:
UPDATE posts
SET title = #{request.title},
	content = #{request.content}
WHERE id = #{postId}
	AND status = 'ACTIVE'

UPDATE spots
SET post_count = post_count + 1
WHERE id = #{spotId}

UPDATE spots
SET post_count = GREATEST(post_count - 1, 0)
WHERE id = #{spotId}

mapper.insert:
INSERT INTO post_images (
	post_id,
	image_url,
	sort_order
)
VALUES (
	#{postId},
	#{imageUrl},
	#{sortOrder}
)
